+public class DateTimeFormatterPatternProviderImpl extends DateTimeFormatterPatternProvider {
+    private static final List<Locale> available =
+        List.of(Locale.UK, Locale.JAPAN, Locale.TAIWAN, Locale.of("ar", "EG"));
